        "visual_html": "<div class=\"w-full sm:w-[480px] bg-white border border-gray-200 rounded-xl shadow-2xl flex flex-col overflow-hidden z-10 transition-transform duration-300 relative group max-w-full mx-auto\">\n<!-- Browser Header -->\n<div class=\"bg-gray-100 border-b border-gray-200 pt-3 px-4 flex items-end gap-2 shrink-0\">\n<div class=\"flex gap-1.5 mb-1.5 mr-2\">\n<div class=\"w-3 h-3 rounded-full bg-gray-300\"></div>\n<div class=\"w-3 h-3 rounded-full bg-gray-300\"></div>\n<div class=\"w-3 h-3 rounded-full bg-gray-300\"></div>\n</div>\n<div class=\"bg-white border-t border-l border-r border-gray-200 rounded-t-lg px-4 py-1.5 text-xs text-gray-700 flex items-center gap-2 min-w-[150px] shadow-sm relative z-10\">\n<svg class=\"w-3.5 h-3.5 text-yellow-500\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n                    Real Online Ruler\n                </div>\n</div>\n<!-- Browser Address Bar -->\n<div class=\"bg-gray-50 border-b border-gray-200 px-4 py-2 flex items-center gap-3 shrink-0\">\n<div class=\"bg-white rounded-md border border-gray-300 px-3 py-1 text-xs text-gray-600 flex-1 truncate flex items-center gap-2 shadow-inner\">\n<svg class=\"w-3.5 h-3.5 text-green-500\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n                    localhost:4321\n                </div>\n</div>\n<!-- Browser Content (The Ruler App) -->\n<div class=\"bg-white flex-1 relative flex flex-col py-6\">\n<!-- Top Ruler -->\n<div class=\"h-8 w-full bg-yellow-100 border-b-2 border-yellow-400 flex justify-between px-4 pt-1 shadow-sm opacity-90 group-hover:opacity-100 transition-opacity\">\n<div class=\"h-full w-0.5 bg-yellow-600\"></div><div class=\"h-3 w-px bg-yellow-500\"></div><div class=\"h-5 w-px bg-yellow-600\"></div><div class=\"h-3 w-px bg-yellow-500\"></div><div class=\"h-full w-0.5 bg-yellow-600\"></div><div class=\"h-3 w-px bg-yellow-500\"></div><div class=\"h-5 w-px bg-yellow-600\"></div><div class=\"h-3 w-px bg-yellow-500\"></div><div class=\"h-full w-0.5 bg-yellow-600\"></div>\n</div>\n<!-- Controls -->\n<div class=\"flex items-center justify-between px-6 pt-6 pb-2 gap-4\">\n<div class=\"flex gap-2\">\n<button class=\"bg-gray-800 text-white px-3 py-1.5 rounded-md text-xs font-semibold shadow-md hover:bg-gray-700 transition-colors\">CM</button>\n<button class=\"bg-white text-gray-800 border border-gray-300 px-3 py-1.5 rounded-md text-xs font-semibold shadow-sm hover:bg-gray-50 transition-colors\">INCHES</button>\n</div>\n<div class=\"flex flex-col items-end\">\n<div class=\"text-[10px] text-gray-500 font-medium uppercase tracking-wider mb-0.5\">Calibration</div>\n<div class=\"text-green-600 font-bold bg-green-50 border border-green-200 px-2.5 py-1 rounded-md text-xs inline-flex items-center gap-1 shadow-sm\">\n<svg class=\"w-3 h-3\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M5 13l4 4L19 7\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n                            MacBook Pro\n                        </div>\n</div>\n</div>\n</div>\n</div>",
        "metadata_html": "<div class=\"mb-4\">\n<h4 class=\"font-medium font-sans text-white text-sm mb-2\">Why I saved this:</h4>\n<ul class=\"list-disc pl-5 font-sans text-sm text-[var(--arsenal-text)] space-y-1\"><li>Abstracted UI framing</li><li>Neutral color palette</li><li>Focuses attention on inner content</li></ul>\n</div>\n<div class=\"mb-6\">\n<h4 class=\"font-medium font-sans text-white text-sm mb-2\">What I can learn:</h4>\n<ul class=\"list-disc pl-5 font-sans text-sm text-[var(--arsenal-text)] space-y-1\"><li>Using pseudo-browser frames for presentations</li><li>Creating depth with borders</li></ul>\n</div>\n<!-- RESTORED: SOURCE METADATA -->\n<div class=\"transparent p-4 rounded border border-white/20 text-sm mt-4 hidden\">\n<div class=\"grid grid-cols-3 gap-y-2 gap-x-4\">\n<div class=\"font-mono text-gray-500\">Creator:</div>\n<div class=\"col-span-2 font-medium text-[var(--text-primary)]\">Tejas Jaware</div>\n<div class=\"font-mono text-gray-500\">Source:</div>\n<div class=\"col-span-2 text-[var(--text-primary)]\"><a class=\"underline font-bold text-[var(--text-primary)] hover:text-indigo-500\" href=\"paper_micro_tool.html\" onclick=\"event.stopPropagation()\">AI Micro-Tools Guide</a></div>\n<div class=\"font-mono text-gray-500 mt-2 pt-2 border-t border-gray-200\">Rights:</div>\n<div class=\"col-span-2 text-gray-500 text-xs italic leading-tight mt-2 pt-2 border-t border-gray-200\">Belongs to original creator. Saved for inspiration.</div>\n</div>\n</div>"
