        "visual_html": "<div class=\"border-2 border-black rounded-xl overflow-hidden bg-white shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] w-full max-w-full mx-auto\">\n<div class=\"bg-gray-100 border-b-2 border-black px-4 py-1.5 flex items-center space-x-2\">\n<svg class=\"w-5 h-5 text-gray-700\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n<span class=\"font-bold text-xs tracking-wide\">SEO TECHNICAL FILES &amp; ANALYTICS</span>\n</div>\n<div class=\"p-4 space-y-1.5 bg-gradient-to-br from-blue-50 to-white\">\n<!-- SEO Files -->\n<div class=\"grid grid-cols-1 md:grid-cols-3 gap-2\">\n<div class=\"bg-white border-2 border-black rounded-lg p-3 shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] hover:-translate-y-1 transition-transform\">\n<div class=\"font-mono font-bold text-blue-600 mb-2 pb-2 border-b border-gray-200\">404.astro</div>\n<ul class=\"text-xs space-y-1 text-gray-600\">\n<li class=\"flex items-start\"><span class=\"text-green-500 mr-1\">\u2713</span> Custom error page</li>\n<li class=\"flex items-start\"><span class=\"text-green-500 mr-1\">\u2713</span> Better UX + SEO</li>\n</ul>\n</div>\n<div class=\"bg-white border-2 border-black rounded-lg p-3 shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] hover:-translate-y-1 transition-transform\">\n<div class=\"font-mono font-bold text-orange-600 mb-2 pb-2 border-b border-gray-200\">sitemap.xml</div>\n<ul class=\"text-xs space-y-1 text-gray-600\">\n<li class=\"flex items-start\"><span class=\"text-green-500 mr-1\">\u2713</span> All URLs listed</li>\n<li class=\"flex items-start\"><span class=\"text-green-500 mr-1\">\u2713</span> Helps Google crawl every page</li>\n</ul>\n</div>\n<div class=\"bg-white border-2 border-black rounded-lg p-3 shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] hover:-translate-y-1 transition-transform\">\n<div class=\"font-mono font-bold text-purple-600 mb-2 pb-2 border-b border-gray-200\">robots.txt</div>\n<ul class=\"text-xs space-y-1 text-gray-600\">\n<li class=\"flex items-start\"><span class=\"text-green-500 mr-1\">\u2713</span> Allow/Disallow rules</li>\n<li class=\"flex items-start\"><span class=\"text-green-500 mr-1\">\u2713</span> Sitemap link included</li>\n</ul>\n</div>\n</div>\n<!-- Google Analytics Setup -->\n<div class=\"border-2 border-black rounded-lg bg-white overflow-hidden shadow-[3px_3px_0px_0px_rgba(0,0,0,1)]\">\n<div class=\"bg-yellow-100 border-b-2 border-black px-3 py-2 flex items-center space-x-2\">\n<div class=\"w-4 h-4 bg-yellow-400 rounded-sm\"></div>\n<span class=\"font-bold text-xs\">Google Analytics Setup Flow</span>\n</div>\n<div class=\"p-4 flex flex-col space-y-2\">\n<div class=\"flex items-center space-x-3 text-xs font-medium\">\n<span class=\"bg-gray-100 border border-black rounded px-2 py-1\">GA4</span>\n<svg class=\"w-4 h-4 text-gray-400\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M14 5l7 7m0 0l-7 7m7-7H3\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n<span class=\"bg-gray-100 border border-black rounded px-2 py-1\">Create Property</span>\n<svg class=\"w-4 h-4 text-gray-400\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M14 5l7 7m0 0l-7 7m7-7H3\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n<span class=\"bg-gray-100 border border-black rounded px-2 py-1\">Web Stream</span>\n<svg class=\"w-4 h-4 text-gray-400\" fill=\"none\" stroke=\"currentColor\" viewbox=\"0 0 24 24\"><path d=\"M14 5l7 7m0 0l-7 7m7-7H3\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\"></path></svg>\n<span class=\"bg-yellow-100 border border-black rounded px-2 py-1 shadow-sm\">Copy G-XXXX tag</span>\n</div>\n<div class=\"bg-gray-900 rounded p-3 font-mono text-[13px] text-gray-300 flex items-start space-x-2\">\n<span class=\"text-blue-400\">Claude Code&gt;</span>\n<span>\"Add this Google Analytics code to header\"</span>\n</div>\n</div>\n</div>\n</div>\n</div>",
